INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B3_L1_C', 'B3', 1, 'C', 'Physical or visual ''machine''', 'Pairs of blocks (e.g. 1 and 2, 2 and 4, 3 and 6)', NULL, NULL, NULL, NULL, 'Show pairs of blocks: 1 gives 2. 2 gives 4. 3 gives 6. Ask: ''What rule is changing the first pile into the second pile?''', 'Identifies the rule as ''double it'' or ''multiply by 2'' (or + same number).', 'Doesn''t see the multiplicative relationship.', 'If I put in 5 blocks, how many will come out? Show me.', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B3_L2_A', 'B3', 2, 'A', 'Input/Output Tables', NULL, NULL, NULL, NULL, NULL, 'Give your child an In/Out table. Ask them to find the missing numbers. Make sure they test their rule on EVERY row to make sure it works.', 'Correctly identifies constant rate rules (+, -, or x) and applies them forward and backward.', 'Guesses the rule based on only one row and gets the rest wrong.', 'How do you know your rule works for EVERY row, not just the ones you checked?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B3_L2_B', 'B3', 2, 'B', 'Input/Output Tables', NULL, NULL, NULL, NULL, NULL, 'Show a table with a ''times'' rule. IN: 2 -> OUT: 6. IN: 4 -> OUT: 12. Find the missing OUT for IN: 5.', 'Identifies the rule as ''multiply by 3'' and gets 15.', 'Thinks the rule is +4, and fails on the second row.', 'Why didn''t +4 work for the second row?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B3_L2_C', 'B3', 2, 'C', 'Input/Output Tables', NULL, NULL, NULL, NULL, NULL, 'Give an incomplete table: IN: __ -> OUT: 15. Rule is +7. ''Work backwards to find IN.''', 'Uses subtraction (15 - 7) to find IN is 8.', 'Adds 15 and 7.', 'If the machine adds 7 on the way OUT, what does it do on the way back IN?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B3_L3_A', 'B3', 3, 'A', 'Counterexample & Falsification', NULL, NULL, NULL, NULL, NULL, 'Show a table: IN(2)->OUT(4). Your friend says ''The rule is +2.'' Do you agree? Show me another row that proves the rule could be ''multiply by 2'' instead.', 'Recognizes that a single data point is not enough to define a linear function. Provides an IN(3)->OUT(6) row to prove multiplication, or IN(3)->OUT(5) for addition.', 'Agrees the rule MUST be +2.', 'What''s the minimum number of examples you need to be SURE of the rule? Is 1 enough? Is 2?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B3_L3_B', 'B3', 3, 'B', 'Counterexample & Falsification', NULL, NULL, NULL, NULL, NULL, 'Show a table: IN(1)->OUT(3), IN(2)->OUT(4), IN(4)->OUT(8). Ask: ''Someone says the rule is +2. Is there a mistake in this table?''', 'Spots that the third row breaks the +2 rule (it should be 4->6).', 'Doesn''t check all rows and assumes the rule is fine.', 'Why must a function machine always follow the exact same rule?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B3_L3_C', 'B3', 3, 'C', 'Counterexample & Falsification', NULL, NULL, NULL, NULL, NULL, 'Say: ''A machine takes in numbers and always spits out 10. Does this machine have a rule?''', 'Realizes the rule is ''OUT is always 10'' or ''multiply by 0 and add 10''.', 'Says it''s broken.', 'Is a rule that ignores the input still a mathematical rule?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B3_L4_A', 'B3', 4, 'A', 'Rule Design & Obfuscation', NULL, NULL, NULL, NULL, NULL, 'Say: ''Design a secret function machine rule. Give me 3 inputs and outputs, and see if I can guess it.'' Try to make it tricky using subtraction.', 'Creates a mathematically sound IN/OUT table and successfully validates the parent''s answer.', 'Makes a table with inconsistent rules.', 'How do you know your machine has only ONE possible rule? Could there be a different rule that gives the same outputs?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B3_L4_B', 'B3', 4, 'B', 'Rule Design & Obfuscation', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Create a 2-step machine. It multiplies by 2, then adds 1. Make a table of 4 inputs and outputs.''', 'Correctly builds the table (e.g., IN: 3 -> OUT: 7).', 'Forgets the second step or applies them in the wrong order.', 'Does order matter? What if you added 1 first, THEN multiplied by 2?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B3_L4_C', 'B3', 4, 'C', 'Rule Design & Obfuscation', NULL, NULL, NULL, NULL, NULL, 'Say: ''Write an In/Out table where the input numbers go backwards (10, 9, 8, 7).''', 'Creates a valid table matching a rule to descending inputs.', 'Cannot handle descending inputs.', 'If the inputs are going backwards, what pattern do you see in the outputs?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B3_L4_M', 'B3', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'Every week, Amara''s sunflower grows taller. In week 1, it was 5 cm. In week 2, it was 8 cm. In week 3, it was 11 cm. Her grandmother asks: ''How tall will it be in week 6 without measuring?''', 'Child identifies the constant growth rate (+3 per week), extends the table, and predicts 20 cm. Reasoning: explains the rule they discovered.', 'Guesses randomly.', 'How do you know it won''t just suddenly grow 10 cm in week 4?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B4_L1_A', 'B4', 1, 'A', 'Physical manipulation', 'Small stones or beans, An empty plate', NULL, NULL, NULL, NULL, 'Put 5 beans on the table. Ask your child to add the beans from the empty plate to the table. Ask: ''How many did you add? How many are there now?'' Do this again with 10 beans.', 'Understands that adding ''nothing'' leaves the group exactly the same size (Identity Property of Addition).', 'Needs to recount the beans every time to know the total.', 'If we had a million beans and added the empty plate, would the number change?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B4_L1_B', 'B4', 1, 'B', 'Physical manipulation', '10 identical objects (like spoons)', NULL, NULL, NULL, NULL, 'Put 10 spoons in a pile. Ask the child to take all 10 away to wash them. Ask: ''What is left?'' Repeat with 3 objects.', 'Realizes subtracting a group from an identical group always leaves 0.', 'Does not recognize the structural certainty of 0.', 'Is there ANY number of spoons where taking them all away wouldn''t leave zero?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B4_L1_C', 'B4', 1, 'C', 'Physical manipulation', 'Two colors of blocks (e.g. 5 red, 8 blue)', NULL, NULL, NULL, NULL, 'Build a train of 5 red and 8 blue blocks. Note the total length. Then build a train of 8 blue and 5 red. Ask: ''Is one longer? Does the order of colors matter?''', 'Observes that order doesn''t change the total length (Commutative property).', 'Re-counts the blocks for both trains instead of trusting the structure.', 'If you know 99 red + 1 blue = 100 blocks, do you need to calculate 1 blue + 99 red?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B4_L2_A', 'B4', 2, 'A', 'Testing claims', NULL, NULL, NULL, NULL, NULL, 'Give your child the claim: ''When you multiply any number by 1, you get the same number back.'' Ask them to test it with small numbers, big numbers, and zero.', 'Uses multiple test cases to verify a mathematical generalization.', 'Only tests one number and stops.', 'You tested 5 pairs. Is 5 enough to prove it''s ALWAYS true? What would be enough?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B4_L2_B', 'B4', 2, 'B', 'Testing claims', NULL, NULL, NULL, NULL, NULL, 'Claim: ''If you double a number, the answer is always even.'' Have them test 3 odd numbers and 3 even numbers.', 'Discovers the claim holds true regardless of what type of number you start with.', 'Cannot follow the testing procedure.', 'Why does multiplying by 2 always force the answer to be even?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B4_L2_C', 'B4', 2, 'C', 'Testing claims', NULL, NULL, NULL, NULL, NULL, 'Claim: ''Adding 9 is the same as adding 10 and subtracting 1.'' Test this on 5, 12, and 24.', 'Confirms the structural shortcut works in all cases.', 'Calculates inconsistently.', 'Why does this trick work for adding 9? Could you make a trick for adding 8?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B4_L3_A', 'B4', 3, 'A', 'Falsification / Counterexamples', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Your friend says: When you multiply two numbers, the answer is ALWAYS bigger than both numbers. Is that true? Try to find just ONE example that proves them wrong.''', 'Finds a counterexample: multiplying by 1 (4 x 1 = 4, not bigger) or by 0 (4 x 0 = 0).', 'Believes the claim is true because they only test large numbers.', 'You found one counterexample. Is one enough to prove the claim is false? Why?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B4_L3_B', 'B4', 3, 'B', 'Falsification / Counterexamples', NULL, NULL, NULL, NULL, NULL, 'Claim: ''If a number ends in 3, it is odd. Therefore, all odd numbers end in 3.'' Is this true? Find a counterexample.', 'Finds an odd number not ending in 3 (e.g., 5, 7, 11).', 'Agrees with the faulty logic.', 'If the first sentence is true, why isn''t the second sentence true?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B4_L3_C', 'B4', 3, 'C', 'Falsification / Counterexamples', NULL, NULL, NULL, NULL, NULL, 'Claim: ''Addition always makes the number bigger.'' Find a counterexample.', 'Adds 0 (e.g., 5 + 0 = 5) to show it doesn''t get *bigger*.', 'Agrees addition always makes it bigger.', 'Why is zero always the best number to test when someone says ''always''?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B4_L4_A', 'B4', 4, 'A', 'Rule formulation', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Look at a calendar. Pick any 2x2 square of numbers. Add the diagonals. Try it on another square. Write a rule for what you found.''', 'Formulates a general rule (the sums of the diagonals in a 2x2 calendar square are always equal) based on specific cases.', 'Just adds them up without seeing the pattern.', 'How do you know your calendar rule works for every 2x2 square, not just the ones you tried?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B4_L4_B', 'B4', 4, 'B', 'Rule formulation', NULL, NULL, NULL, NULL, NULL, 'Ask: ''What happens when you add three consecutive numbers (like 1+2+3, or 5+6+7)? What do you notice about the middle number?''', 'Discovers the sum is always 3 times the middle number.', 'Cannot form a rule.', 'If I picked 10, 11, 12, what would the total be without adding them?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B4_L4_C', 'B4', 4, 'C', 'Rule formulation', NULL, NULL, NULL, NULL, NULL, 'Say: ''Create a math rule of your own that you think is ALWAYS true. Test it to prove it to me.''', 'Comes up with a valid structural property (e.g., adding an even to an even makes an even).', 'Just states a fact like 1+1=2.', 'Could someone else find a counterexample to your rule?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B4_L4_M', 'B4', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'Your friend says ''If I add any two numbers and then subtract one of them, I always get the other one back.'' Is that always true? How would you convince someone who doesn''t believe it?', 'Child tests multiple cases, then attempts a general argument (''because adding and then taking away undoes itself''). Does not need to be told this is about inverse operations.', 'Only tests one case and stops.', 'Can you find any numbers in the whole universe where this wouldn''t work?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B5_L1_A', 'B5', 1, 'A', 'Visual progression', 'Blocks, coins, or drawn shapes', NULL, NULL, NULL, NULL, 'Build step 1 (1 block), step 2 (3 blocks in a triangle), step 3 (6 blocks). Ask: ''How is this pattern growing? Build step 4.''', 'Sees that each step adds a row with one more block than the last row (+2, +3, +4...).', 'Randomly adds blocks without observing the structural change.', 'What do you notice about how many NEW blocks you add each time? Is it always the same?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B5_L1_B', 'B5', 1, 'B', 'Visual progression', 'Pencils or sticks', NULL, NULL, NULL, NULL, 'Make a square with 4 sticks. Next to it, make two connected squares with 7 sticks. Next, three connected squares with 10 sticks. Ask: ''How many sticks for the next one?''', 'Notices you only need 3 more sticks to add a square, not 4.', 'Thinks you need 4 more sticks.', 'Why do we only need 3 new sticks to make a whole new square?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B5_L1_C', 'B5', 1, 'C', 'Visual progression', 'Drawn dots', NULL, NULL, NULL, NULL, 'Draw an ''L'' shape of dots: Step 1 has 3 dots (corner + 1 up + 1 right). Step 2 has 5 dots (corner + 2 up + 2 right). Step 3 has 7 dots. Ask: ''Draw step 4.''', 'Draws corner + 4 up + 4 right (9 dots). Recognizes the +2 growth.', 'Draws a random shape.', 'Where are the new dots being added each time?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B5_L2_A', 'B5', 2, 'A', 'Near calculation', NULL, NULL, NULL, NULL, NULL, 'Show the pattern. Ask your child to build or draw the next two steps, and then count the pieces.', 'Accurately extends the pattern and identifies the constant rate of change (e.g., adding 2 each time).', 'Cannot accurately extend the pattern.', 'If I told you step 100, could you figure it out without drawing all 100 steps? How?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B5_L2_B', 'B5', 2, 'B', 'Near calculation', NULL, NULL, NULL, NULL, NULL, 'Give a sequence: 2, 6, 10, 14... Ask for the 6th number in the pattern.', 'Identifies +4 rule, finds 5th is 18, 6th is 22.', 'Finds the 5th and stops.', 'Did you have to find the 5th number to know the 6th?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B5_L2_C', 'B5', 2, 'C', 'Near calculation', NULL, NULL, NULL, NULL, NULL, 'Show a growing table: Day 1: $2. Day 2: $4. Day 3: $6. Ask: ''How much on Day 5?''', 'Extends table to Day 5 ($10).', 'Guesses a high number without pattern logic.', 'What is the connection between the Day number and the Money amount?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B5_L3_A', 'B5', 3, 'A', 'Far calculation / Rule finding', NULL, NULL, NULL, NULL, NULL, 'Show a pattern that starts with 2 and adds 3 each time (2, 5, 8, 11...). Ask: ''Without drawing the whole thing, how many would be in step 10? How do you know?''', 'Starts linking the step number to the total (e.g., ''10 steps means I added 3 ten times, so 30, plus the 2 I started with'' - intuitive y=mx+b).', 'Tries to draw all 10 steps and makes a counting error.', 'How did you find step 10 without building every step? What shortcut did you use?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B5_L3_B', 'B5', 3, 'B', 'Far calculation / Rule finding', NULL, NULL, NULL, NULL, NULL, 'Show a pattern: 4, 8, 12, 16. Someone says ''Step 10 will be 40 because 10 x 4 is 40.'' Are they right?', 'Understands the multiplicative relationship between the step number and the total.', 'Doesn''t trust the multiplication and tries to count by 4s.', 'Why does multiplication work for this pattern, but not for a pattern like 5, 9, 13?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B5_L3_C', 'B5', 3, 'C', 'Far calculation / Rule finding', NULL, NULL, NULL, NULL, NULL, 'Show two patterns. A: 2, 4, 6, 8. B: 1, 3, 5, 7. Ask: ''How are these patterns similar, and how are they different?''', 'Notes both grow by +2, but start at different numbers.', 'Only sees that the numbers are different.', 'Will pattern B ever catch up to pattern A? Why or why not?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B5_L4_A', 'B5', 4, 'A', 'Pattern generation', NULL, NULL, NULL, NULL, NULL, 'Say: ''Design a growing pattern out of blocks where the 5th step has exactly 17 blocks. Draw it or build it for me.''', 'Works backwards from the constraint to design a consistent linear pattern (e.g., starts with 1, adds 4 each step: 1, 5, 9, 13, 17 or starts with 5, adds 3: 5, 8, 11, 14, 17).', 'Uses random numbers to get to 17, failing to make a consistent pattern.', 'How do you know your pattern is the ONLY one that works? Could someone else design a different pattern that also reaches 17 at step 5?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B5_L4_B', 'B5', 4, 'B', 'Pattern generation', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Create a repeating pattern (like red, blue, red, blue). Now create a growing pattern. Explain the difference.''', 'Creates both and explains that repeating loops, while growing gets bigger.', 'Confuses the two concepts.', 'Can a pattern grow AND repeat at the same time?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B5_L4_C', 'B5', 4, 'C', 'Pattern generation', NULL, NULL, NULL, NULL, NULL, 'Say: ''Make up a pattern that grows very slowly at first, but then grows very fast.''', 'Creates a non-linear pattern (like 1, 2, 4, 8, 16 - doubling).', 'Creates a standard +2 pattern.', 'Why does doubling make the numbers explode so quickly compared to adding?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B5_L4_M', 'B5', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'Nala is building a fence. Each section needs 4 posts. But the sections share posts — the last post of one section is the first post of the next. She has 25 posts. How many complete sections can she build?', 'Child recognises the growing pattern (1st section = 4 posts, each additional section = 3 new posts). Calculates sections: 4 + 3(n-1) ≤ 25 → 8 sections. Does not need ''algebra'' vocabulary.', 'Just divides 25 by 4 and gets 6.', 'Why does the first section need 4 posts, but the next ones only need 3?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);

