INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L1_A', 'G2a', 1, 'A', 'Physical classification', 'Assorted real-world flat objects (e.g., paper, coasters, signs, cutouts)', NULL, NULL, NULL, NULL, 'Put all the items on the table. Say: ''Sort these objects into two piles: those with exactly 4 straight sides, and everything else.''', 'Child accurately sorts all quadrilaterals into one pile, regardless of shape (square, rectangle, rhombus).', 'Child puts all ''regular'' shapes in one pile, ignoring the 4-side constraint, or counts curved edges.', 'Look at this pile with 4 straight sides. Do they all look the same? Why are they in the same pile?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L1_B', 'G2a', 1, 'B', 'Physical classification', 'Sticks or pencils of varying lengths', NULL, NULL, NULL, NULL, 'Give the child sticks. Say: ''Build a shape with exactly 3 straight sides that are closed up tight. Now build a shape with 5 straight sides.''', 'Constructs a triangle and a pentagon. Ensures all corners meet.', 'Constructs open shapes, or uses the wrong number of sticks.', 'If you have 4 sticks, can you only make one type of shape, or many different looking ones?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L1_C', 'G2a', 1, 'C', 'Physical classification', 'Paper and scissors', NULL, NULL, NULL, NULL, 'Cut out a large triangle. Say: ''Cut one corner off this shape. Now count the sides of the new shape. How many are there?''', 'Child cuts a corner, counts the newly created edge, and realizes the new shape has 4 sides (quadrilateral).', 'Child still thinks it''s a triangle because it used to be one.', 'When you cut off one corner, what happens to the number of straight sides?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L2_A', 'G2a', 2, 'A', 'Property Identification', NULL, NULL, NULL, NULL, NULL, 'Show the child 5 different drawn shapes (e.g., square, irregular hexagon, triangle, circle, rhombus). Ask them to count the sides and corners of each, and name them if they can.', 'Correctly counts sides and corners for all shapes, identifying the relationship (sides = corners for polygons).', 'Miscounts sides on irregular shapes, or guesses based on appearance.', 'What do you notice about the number of sides and the number of corners on every shape with straight lines?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L2_B', 'G2a', 2, 'B', 'Property Identification', NULL, NULL, NULL, NULL, NULL, 'Give a description: ''I am thinking of a shape. It has exactly 4 sides. Not all sides are the same length. What shape could it be? Draw one.''', 'Draws a rectangle, trapezoid, or irregular quadrilateral.', 'Draws a square (violating the ''not all same length'' rule) or a triangle.', 'Why couldn''t the shape I''m thinking of be a square?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L2_C', 'G2a', 2, 'C', 'Property Identification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Look around the room. Find 3 things that are rectangles and 1 thing that is a circle. What makes the rectangles different from the circle?''', 'Identifies correct real-world items. Articulates that rectangles have straight edges and corners, while circles are one continuous curve.', 'Picks random items, or cannot explain the difference structurally.', 'Does a rectangle always have to be lying down, or is a tall skinny door still a rectangle?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L3_A', 'G2a', 3, 'A', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a drawing of a ''square'' where one corner doesn''t quite close. Say: ''My friend says this is a square. Are they right?''', 'Identifies that it is not a polygon because it is not closed.', 'Agrees it is a square because of the general shape.', 'If an ant was walking on the lines of this shape, what would happen when it gets to the gap?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L3_B', 'G2a', 3, 'B', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a diamond (rhombus) and say: ''Someone told me this is a diamond, not a square. But if I turn my head, it looks like a square. What makes a square a square?''', 'Explains that a square must have ''L'' shaped corners (right angles), while a diamond can have squished corners.', 'Thinks any tilted square is a diamond.', 'If I take a square piece of paper and turn it, does it stop being a square?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L3_C', 'G2a', 3, 'C', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Draw a very wide, short rectangle. Draw a tall, skinny rectangle. Say: ''A child says these are different shapes entirely. What would you tell them?''', 'Explains they are both rectangles because they both have 4 straight sides and 4 ''L'' corners.', 'Agrees they are different shapes.', 'What rules do both of these shapes follow?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L4_A', 'G2a', 4, 'A', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Draw an alien shape that has exactly 7 straight sides. Make it look as weird as possible, but it MUST be closed. How do you know it''s a polygon?''', 'Draws a closed 7-sided figure. Explains it''s a polygon because it has straight sides and is closed.', 'Draws curved lines, open shapes, or fewer/more than 7 sides.', 'If you showed this to someone, how would you prove it has 7 sides? Can you number them?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L4_B', 'G2a', 4, 'B', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Teach me the difference between a square and a rectangle using two drawings and words.''', 'Draws both correctly. Explains that a square MUST have all 4 sides equal length, while a rectangle can have 2 long and 2 short sides.', 'Cannot articulate the difference in side lengths.', 'Is every square also a type of rectangle? Why or why not?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L4_C', 'G2a', 4, 'C', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Create a sorting game. Draw 5 different shapes. Tell me the secret rule you used to group them into two piles.''', 'Creates a set of shapes and a valid rule (e.g., ''has 4 sides vs doesn''t'', or ''all sides equal vs different'').', 'Cannot formulate a consistent sorting rule.', 'Could someone else figure out your secret rule just by looking at your piles?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L4_M', 'G2a', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'You are helping build a new table. The carpenter says, ''I need a piece of wood for the top. It has 4 straight sides, but only two of them are the same length.'' What does the piece of wood look like?', 'Child describes or draws a trapezoid or irregular quadrilateral, recognizing it cannot be a square or rectangle.', 'Describes a rectangle or square.', 'If it was a rectangle, how many sides would be the same length?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2b_L1_A', 'G2b', 1, 'A', 'Physical exploration', 'Various 3D objects (ball, box, can, cone/party hat)', NULL, NULL, NULL, NULL, 'Give the child the objects. Ask: ''Which of these can roll across the floor? Which can slide? Which can stack on top of each other?'' Let them test.', 'Categorizes correctly by testing. Notices that round surfaces roll, flat surfaces slide and stack.', 'Guesses without testing, or cannot find the pattern.', 'Why can the can slide AND roll, but the box can only slide?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2b_L1_B', 'G2b', 1, 'B', 'Physical exploration', 'A small box, a can, paper, crayon or pencil', NULL, NULL, NULL, NULL, 'Have the child trace the bottom of the box and the bottom of the can on paper. Ask: ''What 2D shape did you make from the 3D shape?''', 'Recognizes the flat faces of 3D objects are 2D shapes (square/rectangle for the box, circle for the can).', 'Traces poorly or cannot name the resulting 2D shapes.', 'If a shape is completely round like a ball, can you trace a flat side?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2b_L1_C', 'G2b', 1, 'C', 'Physical exploration', 'Playdough or clay', NULL, NULL, NULL, NULL, 'Ask the child to make a cube out of playdough. Ask: ''How many flat sides did you have to press to make it look like a block?''', 'Creates a rough cube and counts the 6 faces.', 'Makes a sphere or a flat square.', 'If you rolled it in your hands like a snowball, what shape would it become?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2b_L2_A', 'G2b', 2, 'A', 'Shape Identification', NULL, NULL, NULL, NULL, NULL, 'Show pictures or name objects (e.g., ''a dice'', ''a soup can'', ''a basketball'', ''a tent''). Ask the child to name the mathematical 3D shape.', 'Correctly identifies cube, cylinder, sphere, and triangular prism/cone.', 'Uses 2D names for 3D objects (e.g., calls a sphere a ''circle'').', 'Why is a basketball called a sphere and not a circle?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2b_L2_B', 'G2b', 2, 'B', 'Shape Identification', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Find something in this room that is a cylinder. Now find a rectangular prism.''', 'Finds appropriate objects and justifies the choice based on faces.', 'Cannot find the shapes, or confuses cylinders with spheres.', 'How many circular faces does your cylinder have?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2b_L2_C', 'G2b', 2, 'C', 'Shape Identification', NULL, NULL, NULL, NULL, NULL, 'Say: ''I am thinking of a 3D shape. It has 6 faces, and they are all exactly the same square. What is it?''', 'Identifies a cube.', 'Guesses a rectangle or a sphere.', 'How is a cube different from a rectangular prism like a cereal box?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2b_L3_A', 'G2b', 3, 'A', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a drawing of a cube. Say: ''Someone says this shape has only 3 faces because that is all they can see in the picture. How do you explain they are wrong?''', 'Explains that 3D shapes have a back, bottom, and hidden sides. Uses a real object to prove 6 faces.', 'Agrees there are only 3 faces.', 'Why can''t we draw all the sides of a box on a flat piece of paper at the same time?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2b_L3_B', 'G2b', 3, 'B', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''My friend says a sphere is the best shape for building a tall tower. Why is that a terrible idea?''', 'Explains that spheres have no flat faces to stack, so they will roll away.', 'Doesn''t understand the physical properties of stacking.', 'What is the best shape for building a wall, and why?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2b_L3_C', 'G2b', 3, 'C', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''Someone looked at a cylinder from the top down and said ''That''s a circle!'' Are they right or wrong?''', 'Explains that the *face* is a circle, but the whole object is a cylinder.', 'Agrees it is just a circle.', 'If you look at a cube straight on, what 2D shape do you see?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2b_L4_A', 'G2b', 4, 'A', 'Design', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Design a robot using 3D shapes. Tell me which shape you used for the head, the body, and the wheels. Why did you choose those shapes?''', 'Designs a model, naming the 3D shapes and justifying their physical properties (e.g., cylinders for wheels so it can roll).', 'Just draws a flat picture and uses 2D names.', 'Could your robot stand up if its feet were spheres?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2b_L4_B', 'G2b', 4, 'B', 'Design', NULL, NULL, NULL, NULL, NULL, 'Ask: ''If you had to invent a new box for shipping balls, what 3D shape would the box be and why?''', 'Suggests a rectangular prism (or a larger cylinder) and explains how spheres fit inside.', 'Cannot conceptualize a container.', 'Why are most shipping boxes rectangular prisms instead of cylinders?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2b_L4_C', 'G2b', 4, 'C', 'Design', NULL, NULL, NULL, NULL, NULL, 'Say: ''Write a riddle for a 3D shape. Give 3 clues about its faces, edges, or if it can roll. Let me guess.''', 'Writes a solvable riddle using structural properties of a 3D shape.', 'Gives vague clues like ''it''s blue''.', 'What is the most helpful clue you gave me?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2b_L4_M', 'G2b', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'We need to pack these delicate glass spheres into a box. If we just put them in a big square box, they will roll around and break. What should we do to pack them safely?', 'Child suggests using cylinders (like tubes) or creating smaller cube compartments to hold them still.', 'Suggests just putting them in the box.', 'Why does a sphere roll, and how does a tube stop it?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2c_L1_A', 'G2c', 1, 'A', 'Physical measurement', 'A ruler with cm markings, a book, a pencil', NULL, NULL, NULL, NULL, 'Show the child how to line up the ''0'' mark of the ruler with the edge of the book. Ask them to measure the book and the pencil.', 'Lines up the 0 mark (not the edge of the ruler itself if different) and reads the closest cm mark at the other end.', 'Starts measuring from the ''1'' mark, or reads the wrong side of the ruler (inches).', 'Why do we start at the zero line instead of the edge of the stick?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2c_L1_B', 'G2c', 1, 'B', 'Physical measurement', 'String, scissors, ruler', NULL, NULL, NULL, NULL, 'Ask the child to cut a piece of string that is exactly 15 cm long.', 'Measures the string against the ruler starting at 0, and cuts accurately.', 'Cuts first and measures later, or measures from 1.', 'If you wanted a string twice as long, how many cm would it be?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2c_L1_C', 'G2c', 1, 'C', 'Physical measurement', 'A meter stick or measuring tape', NULL, NULL, NULL, NULL, 'Show how big 1 meter is. Ask: ''Find 3 things in this room that are longer than 1 meter, and 3 things that are shorter.''', 'Uses the meter as a benchmark to compare lengths.', 'Guesses wildly without comparing.', 'Is your bed longer or shorter than a meter? How do you know?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2c_L2_A', 'G2c', 2, 'A', 'Measurement estimation and calculation', NULL, NULL, NULL, NULL, NULL, 'Show a picture of a pencil lying next to a broken ruler. The pencil starts at the 3cm mark and ends at the 10cm mark. Ask: ''How long is the pencil?''', 'Subtracts 3 from 10 (or counts the spaces) to find the length is 7cm.', 'Says the pencil is 10cm long.', 'If the pencil moved to start at the 5cm mark, where would it end?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2c_L2_B', 'G2c', 2, 'B', 'Measurement estimation and calculation', NULL, NULL, NULL, NULL, NULL, 'Ask: ''If you have a string that is 12 cm long, and you tie it to a string that is 8 cm long, how long is the new string?''', 'Adds 12 + 8 = 20 cm.', 'Subtracts them.', 'Does tying them together make a bigger number or a smaller number?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2c_L2_C', 'G2c', 2, 'C', 'Measurement estimation and calculation', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Would you measure a football field in centimeters or meters? Why?''', 'Chooses meters, explaining that cm are too small and would take too long/be a huge number.', 'Chooses centimeters.', 'What would be a good thing to measure in centimeters?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2c_L3_A', 'G2c', 3, 'A', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a drawing of a stick being measured. The ruler''s ''1'' mark is lined up with the left edge of the stick. The right edge is at ''8''. Someone says the stick is 8cm long. Are they right?', 'Explains that because they started at 1 instead of 0, the stick is actually 7cm long.', 'Agrees the stick is 8cm long.', 'If you start counting from 1 instead of 0, what happens to your final answer?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2c_L3_B', 'G2c', 3, 'B', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''My friend measured a table and said it is 50 long. What is wrong with their answer?''', 'Notices the missing unit (cm vs m).', 'Thinks 50 is a fine answer.', 'Why is ''50'' a useless answer if you want to buy a tablecloth?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2c_L3_C', 'G2c', 3, 'C', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a ruler drawn with unequal spacing between the numbers. Say: ''Can I use this to measure my shoe?''', 'Explains that standard measurement requires equal units. A ''cm'' must always be exactly the same size.', 'Says yes, just count the numbers.', 'Why did people invent rulers instead of just using their feet to measure things?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2c_L4_A', 'G2c', 4, 'A', 'Design and application', NULL, NULL, NULL, NULL, NULL, 'Ask: ''If we didn''t have a ruler, invent a new standard unit of measurement using something in this room. Tell me how you would make sure everyone measures the exact same way.''', 'Chooses an object (e.g., a specific block) and explains how to lay it end-to-end with no gaps or overlaps.', 'Suggests using something variable (like hands) without standardizing.', 'If your friend used THEIR thumb, and you used YOUR thumb, would you get the same number?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2c_L4_B', 'G2c', 4, 'B', 'Design and application', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Draw a map showing a path from a tree to a house. Write a math problem about how long the total path is.''', 'Draws a path with multiple segments, labels them with lengths (e.g., 5m, 10m), and creates an addition problem.', 'Draws a path without numbers or units.', 'If someone walks there and back, how far do they walk?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2c_L4_C', 'G2c', 4, 'C', 'Design and application', NULL, NULL, NULL, NULL, NULL, 'Say: ''Teach me how to measure a curvy line, like a snake drawn on paper, using a piece of string and a straight ruler.''', 'Explains laying the string along the curve, marking it, then straightening the string against the ruler.', 'Tries to bend the ruler or says it''s impossible.', 'Why can''t you just measure the snake from head to tail with the straight ruler?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2c_L4_M', 'G2c', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'Aunty needs a new string for her clothesline. The distance between the two poles is exactly 5 giant steps. She wants to go to the shop to buy the string. What should she tell the shopkeeper?', 'Child realizes ''giant steps'' is not a standard unit and suggests measuring the steps with a ruler or meter stick first to get a number in meters or cm.', 'Says ''buy 5 giant steps of string''.', 'Will the shopkeeper''s giant step be the same size as Aunty''s?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2d_L1_A', 'G2d', 1, 'A', 'Physical comparison', 'A 1kg bag of sugar or flour, a small toy, a large empty box', NULL, NULL, NULL, NULL, 'Let the child hold the 1kg bag in one hand. Call this ''one kilogram''. Let them hold the small toy, then the empty box. Ask: ''Which is heavier than 1kg? Which is lighter?''', 'Uses the 1kg bag as a benchmark to compare mass, realizing the large box can be lighter than the small bag.', 'Guesses the box is heavier just because it is bigger.', 'Does being bigger always mean being heavier?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2d_L1_B', 'G2d', 1, 'B', 'Physical comparison', 'A 1-litre bottle of water, a small cup, a large bowl, water', NULL, NULL, NULL, NULL, 'Show the 1-litre bottle. Ask: ''Do you think this water will fit in the small cup? What about the big bowl? Let''s pour it to find out.''', 'Observes that ''capacity'' means how much it holds, and visually estimates if containers hold more or less than 1 litre.', 'Thinks the tall skinny cup holds more than the wide bowl.', 'If I pour the water from the tall bottle into the wide bowl, is there still 1 litre of water?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2d_L1_C', 'G2d', 1, 'C', 'Physical measurement', 'Kitchen scale, various household items', NULL, NULL, NULL, NULL, 'Show how to put an item on the scale and read the number in grams/kg. Ask them to weigh 3 different items.', 'Places items correctly and reads the number.', 'Pushes down on the scale or doesn''t look at the numbers.', 'What happens to the numbers on the scale when you add another item?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2d_L2_A', 'G2d', 2, 'A', 'Estimation and calculation', NULL, NULL, NULL, NULL, NULL, 'Ask: ''If a bag of rice is 5 kg, and a bag of beans is 3 kg, how many kg of food do we have altogether?''', 'Adds 5 + 3 = 8 kg.', 'Just adds numbers without understanding the context.', 'If we ate 2 kg of rice, how much food would be left?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2d_L2_B', 'G2d', 2, 'B', 'Estimation and calculation', NULL, NULL, NULL, NULL, NULL, 'Say: ''A recipe needs 2 litres of water. You have a 1-litre jug. How many jugs do you need to pour in?''', 'Understands the unit translation (1+1=2).', 'Cannot figure out how to use the 1-litre jug.', 'What if the recipe needed 5 litres?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2d_L2_C', 'G2d', 2, 'C', 'Estimation and calculation', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Which is a better estimate for the weight of a bicycle: 15 kg or 150 kg?''', 'Chooses 15 kg, relating 150 kg to something impossibly heavy (like a car or huge animal).', 'Guesses 150 kg.', 'What is something that might weigh 150 kg?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2d_L3_A', 'G2d', 3, 'A', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''A child says: ''My glass is taller than your mug, so my glass definitely holds more water.'' Are they right?''', 'Explains that capacity depends on width AND height. A short, wide mug can hold more than a tall, skinny glass.', 'Agrees the taller glass holds more.', 'How could we prove which one holds more water?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2d_L3_B', 'G2d', 3, 'B', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''Someone wrote: 5 kg + 3 litres = 8. What is wrong with this math?''', 'Explains you cannot add mass (kg) and capacity (litres) together.', 'Thinks it''s fine because 5+3=8.', 'If I have 5 apples and 3 rocks, do I have 8 apple-rocks?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2d_L3_C', 'G2d', 3, 'C', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show two boxes of the same size. One is full of books, one is empty. Say: ''My friend says these weigh the same because they are the same size.''', 'Explains that volume (size) is not the same as mass (weight).', 'Agrees they weigh the same.', 'If I filled one box with air and one with water, which would be heavier?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2d_L4_A', 'G2d', 4, 'A', 'Design', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Write a recipe for a magic potion. You must include 3 liquids measured in litres and 2 solid ingredients measured in kg. What is the total volume of liquid?''', 'Creates a recipe with appropriate units and correctly sums the liquid volumes.', 'Mixes up kg and litres, or cannot add them.', 'Why didn''t you add the kg to the litres to find the total liquid?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2d_L4_B', 'G2d', 4, 'B', 'Design', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Design a challenge for me where I have to figure out how many 2-litre bottles I need to fill a giant 20-litre fish tank.''', 'Creates the division/repeated addition problem (10 bottles).', 'Makes an unsolvable problem.', 'What if I only had a 5-litre bucket? How many times would I fill it?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2d_L4_C', 'G2d', 4, 'C', 'Design', NULL, NULL, NULL, NULL, NULL, 'Say: ''Teach me how to balance a scale if I put a 5 kg weight on one side, but I only have 1 kg and 2 kg weights to put on the other side.''', 'Suggests combinations like five 1kg weights, or two 2kg and one 1kg weight.', 'Cannot find a combination to equal 5.', 'Is there more than one way to make 5 kg with those smaller weights?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2d_L4_M', 'G2d', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'We are going on a long hike. We have a big, light sleeping bag and a small, heavy rock. Which one should go in the backpack to make it easier to carry?', 'Child distinguishes between mass (heavy rock) and volume (big sleeping bag), choosing to leave the heavy rock behind.', 'Leaves the sleeping bag because it is ''bigger''.', 'Does taking up a lot of space mean something is hard to carry?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2e_L1_A', 'G2e', 1, 'A', 'Physical measurement', 'A book, string or yarn', NULL, NULL, NULL, NULL, 'Ask: ''Can you use this string to measure exactly how far it is to walk all the way around the edge of this book?'' Let them wrap the string and then stretch it out.', 'Wraps the string tightly around the perimeter, then measures the full string length, understanding it represents the continuous boundary.', 'Only measures one side, or doesn''t keep the string tight on the corners.', 'Why does the string get so long when we straighten it out?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2e_L1_B', 'G2e', 1, 'B', 'Physical measurement', 'A rectangular table, hands/spans', NULL, NULL, NULL, NULL, 'Say: ''Let''s measure the distance around the edge of this table using only our hands. Walk all the way around it placing hand over hand. How many hands is it?''', 'Understands that ''around'' means adding up all four sides continuously.', 'Only measures the two long sides.', 'If an ant wanted to walk the edge of the table and get back to where it started, would it have to walk all four sides?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2e_L1_C', 'G2e', 1, 'C', 'Physical measurement', 'Grid paper or floor tiles', NULL, NULL, NULL, NULL, 'Tape a square on the floor tiles. Say: ''Walk the line of the tape. How many steps (tiles) did you take to get all the way back to the start?''', 'Counts the total steps around the boundary.', 'Counts the tiles inside the square.', 'Are you walking on the inside or on the edge? Why does that matter?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2e_L2_A', 'G2e', 2, 'A', 'Calculation from drawing', NULL, NULL, NULL, NULL, NULL, 'Show a drawing of a triangle with sides labeled 5cm, 6cm, and 7cm. Ask: ''What is the distance around this whole shape?''', 'Adds all three sides (5+6+7=18cm) to find the perimeter.', 'Only adds two sides, or multiplies.', 'If you only added 5 and 6, where would the ant stop walking?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2e_L2_B', 'G2e', 2, 'B', 'Calculation from drawing', NULL, NULL, NULL, NULL, NULL, 'Say: ''A square has one side that is 4 cm long. What is the distance all the way around?''', 'Knows that a square has 4 equal sides, so 4+4+4+4=16cm.', 'Says 4cm, or asks for the other sides.', 'Why didn''t I need to tell you how long the other three sides are?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2e_L2_C', 'G2e', 2, 'C', 'Calculation from drawing', NULL, NULL, NULL, NULL, NULL, 'Show a rectangle where only the top (8cm) and left side (3cm) are labeled. Ask: ''What is the perimeter?''', 'Knows opposite sides are equal. Calculates 8+3+8+3=22cm.', 'Only adds 8+3=11cm.', 'What do you know about the top and bottom of a rectangle?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2e_L3_A', 'G2e', 3, 'A', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a rectangle labeled 5 and 3. Someone calculated the perimeter as 5 + 3 = 8. Ask: ''What did they forget?''', 'Explains they only measured halfway around the shape.', 'Agrees the perimeter is 8.', 'If they only walked 8 steps, did they make it back to the start?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2e_L3_B', 'G2e', 3, 'B', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Draw two different shapes: a long skinny rectangle (10x1) and a square (3x3). Both have perimeter ~22-24, but look different. Say: ''Can two shapes that look completely different have the exact same perimeter?''', 'Yes, perimeter is just the length of the string needed to go around. You can bend that string into any shape.', 'No, different shapes must have different perimeters.', 'If I take a string loop and stretch it into a triangle, then a square, did the string change length?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2e_L3_C', 'G2e', 3, 'C', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show an ''L'' shaped room. The perimeter is calculated by adding all 6 sides. Say: ''A builder only added the 4 outside corners. Is that the perimeter?''', 'Explains you MUST count every single straight edge that touches the outside.', 'Agrees you only need 4 numbers.', 'What happens to the fence if you skip those inner walls?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);